#include <stdio.h>
#include <stdlib.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int *a = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) scanf("%d", &a[i]);
        int cnt = 0, hasAdj = 0;
        for (int i = 0; i < N; ++i) {
            if (a[i] == i+1) {
                ++cnt;
                if (i+1 < N && a[i+1] == i+2) hasAdj = 1;
            }
        }
        int ans = cnt - (hasAdj ? 1 : 0);
        printf("%d\n", ans);
        free(a);
    }
    return 0;
}

